sp_widget.client_script:
api.controller = function() {
  var c = this;

  c.patient = {};

  c.submitForm = function() {
    c.data.action = 'createPatient';
    c.data.newPatient = c.patient;

    c.server.update().then(function() {
      c.data.action = null; 
    });
  };

  c.clearForm = function() {
    c.patient = {};
    c.data.successMessage = null;
    c.data.newP = null;
  };

  // print functions
  c.printID = function() {
    // gram html and print
    var printContents = document.getElementById('printable-id').innerHTML;

    // temp wind
    var printWindow = window.open('', '_blank', 'width=800,height=600');


printWindow.document.write('<html><head><title>Print Patient ID</title>');
    printWindow.document.write('<style>');
    printWindow.document.write('body { margin: 0; padding: 40px; display: flex; justify-content: center; font-family: sans-serif; -webkit-print-color-adjust: exact; print-color-adjust: exact; }');
    printWindow.document.write('.id-card-wrapper { position: relative; width: 600px; height: 380px; border-radius: 15px; overflow: hidden; }');
    printWindow.document.write('.id-bg-img { position: absolute; top: 0; left: 0; width: 100%; height: 100%; z-index: 1; }');


    printWindow.document.write('.id-barcode { position: absolute; bottom: 35px; left: 20px; width: 180px; height: 45px; z-index: 2; mix-blend-mode: multiply; }');

    printWindow.document.write('.id-text { position: absolute; z-index: 2; color: #1e293b; font-weight: bold; }');


    printWindow.document.write('.id-number { top: 120px; left: 250px; font-size: 18px; }');
    printWindow.document.write('.id-fullname { top: 175px; left: 250px; font-size: 18px; }');
    printWindow.document.write('.id-age { top: 232px; left: 250px; font-size: 18px; }');
    printWindow.document.write('.id-gender { top: 232px; left: 350px; font-size: 18px; }');
    printWindow.document.write('.id-date { top: 290px; left: 250px; font-size: 18px; }');


    printWindow.document.write('.id-footer { bottom: 16px; left: 15px; font-size: 10.5px; width: 570px; text-align: center; }');

    printWindow.document.write('</style></head><body>');

    printWindow.document.write(printContents);
    printWindow.document.write('</body></html>');
    printWindow.document.close();

    // wait for the bg image to sho first
    setTimeout(function() {
      printWindow.focus();
      printWindow.print();
    }, 800);
  };
};

sp_widget.css:
/* form general containerr */
.form-container {
  background: #ffffff;
  border-radius: 24px;
  box-shadow: 0 10px 40px rgba(0, 0, 0, 0.03);
  max-width: 850px;
  margin: 40px auto;
  font-family: 'Inter', system-ui, sans-serif;
  overflow: hidden;
  border: 1px solid #f1f5f9;
}

.form-header { padding: 32px 40px 20px 40px; background: #ffffff; }
.form-header h3 { margin: 0; color: #1e293b; font-size: 24px; font-weight: 700; letter-spacing: -0.5px; }
.form-header p { margin: 8px 0 0 0; color: #94a3b8; font-size: 14px; }

form { padding: 0 40px 30px 40px; }
.form-row { display: flex; gap: 24px; margin-bottom: 20px; }
.form-group { flex: 1; display: flex; flex-direction: column; }

label {
  font-size: 13px; font-weight: 600; color: #475569;
  margin-bottom: 8px; display: flex; align-items: center; gap: 4px;
}
.required { color: #f43f5e; }

.form-control {
  height: 48px; 
  padding: 0 16px; 
  line-height: 48px; 
  border: 1px solid #e2e8f0;
  border-radius: 14px;
  font-size: 14px;
  color: #1e293b;
  background-color: #f8fafc;
  transition: all 0.2s ease;
  box-sizing: border-box; 
}

.form-control:focus {
  border-color: #6366f1;
  background-color: #ffffff;
  outline: none;
  box-shadow: 0 0 0 4px rgba(99, 102, 241, 0.1);
}

.form-footer {
  padding: 24px 40px;
  background-color: #fbfcfe;
  display: flex;
  justify-content: flex-end;
  align-items: center;
  gap: 16px;
  border-top: 1px solid #f1f5f9;
}

.btn-clear {
  background: transparent; border: 1px solid #e2e8f0; color: #475569;
  padding: 12px 20px; font-weight: 600; cursor: pointer; border-radius: 14px;
}

.btn-submit {
  background: linear-gradient(135deg, #6366f1, #4f46e5);
  border: none; color: #ffffff;
  padding: 0 32px; 
  height: 48px; 
  line-height: 48px;
  border-radius: 14px;
  font-weight: 600;
  cursor: pointer;
  box-shadow: 0 4px 12px rgba(99, 102, 241, 0.2);
  transition: all 0.2s;
}

.btn-submit:hover { transform: translateY(-1px); box-shadow: 0 6px 20px rgba(99, 102, 241, 0.3); }

.alert-success { padding: 20px 40px; background-color: #ffffff; }

/* the id card css */
.id-card-preview {
  display: flex;
  justify-content: center;
  margin-top: 20px;
}

.id-card-wrapper {
  position: relative;
  width: 600px;
  height: 380px;
  overflow: hidden;
  border-radius: 15px;
  box-shadow: 0 10px 30px rgba(0,0,0,0.15);
  font-family: 'Inter', system-ui, sans-serif;
}

.id-bg-img {
  position: absolute;
  top: 0; left: 0;
  width: 100%; height: 100%;
  z-index: 1;
}


.id-barcode {
  position: absolute;
  bottom: 80px;
  left: 35px;
  width: 180px;
  height: 45px;
  z-index: 2;
  mix-blend-mode: multiply;
  transform: scale(0.8);
  transform-origin: left bottom; 
}

.id-text {
  position: absolute;
  z-index: 2;
  color: #1e293b;
  font-weight: bold; 
}


.id-number   { top: 120px; left: 250px; font-size: 18px; } 
.id-fullname { top: 175px; left: 250px; font-size: 18px; } 
.id-age      { top: 228px; left: 250px; font-size: 18px; } 
.id-gender   { top: 228px; left: 350px; font-size: 18px; } 
.id-date     { top: 290px; left: 250px; font-size: 18px; } 


.id-footer {
  bottom: 18px;
  left: 15px;
  font-size: 13px; 
  font-weight: 500;
  width: 570px;
  text-align: center;
  color: #1e293b;
}

sp_widget.script:
(function() {
  if (input && input.action == 'createPatient') {
    var pGR = new GlideRecord('x_1954503_smartc_0_patient');
    pGR.initialize();

    pGR.setValue('full_name', input.newPatient.full_name);
    pGR.setValue('age', input.newPatient.age);
    pGR.setValue('gender', input.newPatient.gender); 
    pGR.setValue('medical_department', input.newPatient.department); 
   // pGR.setValue('symptoms', input.newPatient.symptoms);

    var newSysId = pGR.insert();

    if (newSysId) {
      // fetch the newly created record to get auto-generated fields
      var fetchNew = new GlideRecord('x_1954503_smartc_0_patient');
      fetchNew.get(newSysId);

      // 2. format the date as the 
      var gd = new GlideDate();
      gd.setValue(fetchNew.getValue('sys_created_on'));
      var formattedDate = gd.getByFormat("dd MMM yyyy");

      // data for the id
      data.newP = {
        number: fetchNew.getValue('number'),
        full_name: fetchNew.getValue('full_name'),
        age: fetchNew.getValue('age'),
        gender: fetchNew.getValue('gender'),
        registered_date: formattedDate,
        department: fetchNew.getDisplayValue('medical_department') || 'Pending',
        doctor: fetchNew.getDisplayValue('assigned_doctor') || 'Pending',
        nurse: fetchNew.getDisplayValue('u_assigned_nurse') || 'Pending'
      };

      data.successMessage = "Patient " + input.newPatient.full_name + " successfully Registered.";
    }
  }
})();
